CREATE TABLE Colorectal_Cancer_Exome_Dataset (
    Sl_No INT PRIMARY KEY,
    NCB_SRA_ID VARCHAR(50),
    Cancer_Name VARCHAR(255),
    Design VARCHAR(255),
    Instrument VARCHAR(255),
    Strategy VARCHAR(255),
    Source VARCHAR(255),
    Selection VARCHAR(255),
    Layout VARCHAR(255),
    Isolate VARCHAR(255),
    BioProject VARCHAR(255),
    BioSample VARCHAR(255),
    Url VARCHAR(255)    Default ''                      -- Url
);


